/* ===========================================================================
 * Rendering lifecycle
 *
 * Two interrelated startApp/render bugs are pinned here:
 *
 *  (a) LISTENER LEAK — startApp calls subscribe(render) and used to throw away
 *      the returned unsubscribe function, so every re-mount left the previous
 *      mount's hashchange listener on `window`. (happy-dom dedups identical
 *      function references, so this leak is latent rather than multiplicative
 *      in this environment, but the cleanup contract is still asserted via the
 *      addEventListener/removeEventListener spies below.)
 *  (b) RENDER RACE — render() is async; two rapid navigations let a slower
 *      fetch overwrite a fresher one's results. The fix aborts a superseded
 *      render after each await.
 * ========================================================================= */
describe('rendering lifecycle', () => {
  describe('hashchange listener cleanup on re-mount', () => {
    /**
     * Mount the app `n` times into fresh containers, the way `setup()` does.
     * Returns nothing; used to drive repeated startApp() calls with the spies
     * already installed so every subscribe/unsubscribe is captured.
     */
    function mountNTimes(n: number): void {
      for (let i = 0; i < n; i++) {
        document.body.innerHTML = '';
        window.location.hash = '';
        const root = document.createElement('div');
        document.body.append(root);
        startApp(root);
      }
    }

    function hashchangeCalls(
      spy: ReturnType<typeof vi.spyOn>,
    ): Array<{ type: string; callback: EventListenerOrEventListenerObject }> {
      return spy.mock.calls
        .map(([type, callback]) => ({ type: String(type), callback }))
        .filter((c) => c.type === 'hashchange');
    }

    it('subscribes exactly one hashchange listener per mount', async () => {
      const addSpy = vi.spyOn(window, 'addEventListener');

      mountNTimes(3);
      await flush();

      // Each startApp() subscribes render exactly once.
      expect(hashchangeCalls(addSpy)).toHaveLength(3);
    });

    it("unsubscribes the previous mount's hashchange listener on every re-mount", async () => {
      const addSpy = vi.spyOn(window, 'addEventListener');
      const removeSpy = vi.spyOn(window, 'removeEventListener');

      const N = 4;
      mountNTimes(N);
      await flush();

      const adds = hashchangeCalls(addSpy);
      const removes = hashchangeCalls(removeSpy);

      // Robust to test ordering: the 1st mount in *this* test may additionally
      // tear down a listener left over by an earlier test, so we only assert a
      // lower bound. The invariant that matters is that every re-mount removes
      // its predecessor — i.e. at least (N − 1) hashchange removals happened.
      // The leaky implementation performs ZERO removals.
      expect(adds).toHaveLength(N);
      expect(removes.length).toBeGreaterThanOrEqual(N - 1);
      // Every removal targets the same render callback that was subscribed.
      expect(removes.length).toBeGreaterThan(0);
      for (const r of removes) {
        expect(typeof r.callback).toBe('function');
        expect(adds.some((a) => a.callback === r.callback)).toBe(true);
      }
    });
  });

  describe('render race (superseded fetch is discarded)', () => {
    /**
     * Drive a browse render for `path` whose fetch is held open until the
     * caller invokes `release()`. All other browse paths resolve immediately.
     */
    function stubHeldBrowse(heldPath: string): { release: () => void } {
      let release!: () => void;
      const held = new Promise<Response>((resolve) => {
        release = () =>
          resolve(
            mockResponse({
              body: browseResult({
                path: heldPath,
                entries: [
                  fileEntry({
                    name: 'child-of-' + heldPath,
                    path: joinPathHelper(heldPath, 'child-of-' + heldPath),
                  }),
                ],
                fileCount: 1,
                totalSize: 1,
              }),
            }),
          );
      });

      fetchMock.mockImplementation(async (url, init) => {
        const u = String(url);
        const method = (init?.method ?? 'GET').toUpperCase();
        if (method === 'GET' && u.includes('/browse')) {
          const path = decodeURIComponent(u.split('path=')[1] ?? '');
          if (path === heldPath) {
            return held;
          }
          return mockResponse({
            body: browseResult({
              path,
              entries: [
                fileEntry({
                  name: 'child-of-' + path,
                  path: joinPathHelper(path, 'child-of-' + path),
                }),
              ],
              fileCount: 1,
              totalSize: 1,
            }),
          });
        }
        return mockResponse({ status: 200, body: {} });
      });

      return { release };
    }

    it('does not let a slower, superseded browse overwrite the latest results', async () => {
      const { release } = stubHeldBrowse('slow');

      const { results } = setup();
      await flush(); // settle the initial render for the default route

      // Navigate to 'slow' (its fetch is held), then — before it resolves — to
      // 'fast'. In happy-dom each hash assignment fires `hashchange` and thus
      // render() synchronously, so both fetches are issued in order and the
      // 'slow' render is suspended at its await when 'fast' starts.
      navigate(toBrowseHash('slow'));
      navigate(toBrowseHash('fast'));
      await flush(); // 'fast' resolves first and commits

      expect(results.textContent).toContain('child-of-fast');
      expect(results.textContent).not.toContain('child-of-slow');

      // The slow fetch finally resolves LAST. Its stale data must be discarded
      // (a newer render owns the slot) and must NOT clobber the fresh results.
      release();
      await flush();

      expect(results.textContent).toContain('child-of-fast');
      expect(results.textContent).not.toContain('child-of-slow');
    });

    it('does not let a superseded browse update the breadcrumb or status', async () => {
      const { release } = stubHeldBrowse('slow');

      const { breadcrumb, status } = setup();
      await flush();

      navigate(toBrowseHash('slow'));
      navigate(toBrowseHash('fast'));
      await flush();

      // The fresh render owns the breadcrumb / status for 'fast'.
      expect(breadcrumb.textContent).toContain('fast');
      expect(status.textContent).toContain('1 files');

      release();
      await flush();

      // The superseded 'slow' render must not have touched them.
      expect(breadcrumb.textContent).toContain('fast');
      expect(breadcrumb.textContent).not.toContain('slow');
      expect(status.textContent).toContain('1 files');
    });

    it('still renders the latest navigation when fetches resolve in order', async () => {
      // Control case: a single navigation (no race) still commits normally,
      // so the race guard does not swallow a non-superseded render.
      const { results } = setup({ hash: toBrowseHash('solo') });
      await flush();

      expect(results.textContent).toContain('child-of-solo');

      navigate(toBrowseHash('next'));
      await flush();

      expect(results.textContent).toContain('child-of-next');
      expect(results.textContent).not.toContain('child-of-solo');
    });
  });
});

/* ===========================================================================
 * Search loading spinner
 *
 * `render()` shows a spinner (a `.search-spinner` div wrapping a
 * `.bi-arrow-repeat.spinning` icon) in the results container while a SEARCH
 * fetch is in flight, and never for a browse route. It is removed once the
 * search table renders (renderSearch clears `innerHTML` first) or, on failure,
 * once the error handler sets `textContent`. The existing race-token guard
 * also keeps a superseded search render from re-adding a stale spinner.
 * ========================================================================= */
describe('search loading spinner', () => {
  /**
   * Drive a search render for `query` whose fetch is held open until the
   * caller invokes `release()`. All other requests resolve immediately.
   */
  function stubHeldSearch(heldQuery: string): { release: () => void } {
    let release!: () => void;
    const held = new Promise<Response>((resolve) => {
      release = () =>
        resolve(
          mockResponse({
            body: {
              query: heldQuery,
              path: '',
              results: [
                fileEntry({
                  name: 'result-for-' + heldQuery,
                  path: joinPathHelper('docs', 'result-for-' + heldQuery),
                }),
              ],
            } as SearchResult,
          }),
        );
    });

    fetchMock.mockImplementation(async (url, init) => {
      const u = String(url);
      const method = (init?.method ?? 'GET').toUpperCase();
      if (method === 'GET' && u.includes('/search')) {
        const afterQuery = u.slice(u.indexOf('query=') + 6);
        const query = decodeURIComponent(afterQuery.split('&')[0]);
        if (query === heldQuery) {
          return held;
        }
        return mockResponse({
          body: {
            query,
            path: '',
            results: [
              fileEntry({
                name: 'result-for-' + query,
                path: joinPathHelper('docs', 'result-for-' + query),
              }),
            ],
          } as SearchResult,
        });
      }
      if (method === 'GET' && u.includes('/browse')) {
        const raw = u.split('path=')[1] ?? '';
        const path = decodeURIComponent(raw);
        const childName = 'child-of-' + (path || 'root');
        return mockResponse({
          body: browseResult({
            path,
            entries: [fileEntry({ name: childName, path: joinPathHelper(path, childName) })],
            fileCount: 1,
            totalSize: 10,
          }),
        });
      }
      return mockResponse({ status: 200, body: {} });
    });

    return { release };
  }

  it('shows a spinner (.search-spinner with a spinning icon) while a search fetch is in flight', async () => {
    const { release } = stubHeldSearch('slow-query');
    const { results } = setup({ hash: toSearchHash('slow-query', '') });
    await flush(); // settle the initial browse render

    // Navigate to the search — the fetch is held
    navigate(toSearchHash('slow-query', ''));
    await flush();

    // The spinner should be visible in the results area
    const spinner = results.querySelector('.search-spinner');
    expect(spinner, 'a .search-spinner element must exist during an in-flight search').toBeTruthy();
    const spinningIcon = spinner!.querySelector('.bi-arrow-repeat.spinning');
    expect(spinningIcon, 'the spinner must contain a .bi-arrow-repeat.spinning icon').toBeTruthy();

    // Release the held fetch — results should render and the spinner should be gone
    release();
    await flush();

    expect(results.querySelector('.search-spinner')).toBeNull();
    expect(results.querySelector('table')).toBeTruthy();
    expect(results.textContent).toContain('result-for-slow-query');
  });

  it('does NOT show a spinner during browse fetches', async () => {
    const { results } = setup({ hash: toBrowseHash('docs') });
    await flush();

    expect(results.querySelector('.search-spinner')).toBeNull();
  });

  it('removes the spinner when a search fetch fails (error message replaces it)', async () => {
    fetchMock.mockImplementation(async () => mockResponse({ status: 500, text: 'boom' }));
    const { results } = setup({ hash: toSearchHash('fail-query', '') });
    await flush();

    expect(results.querySelector('.search-spinner')).toBeNull();
    expect(results.textContent).toContain('Error');
  });

  it('a superseded search render does not leave a stale spinner', async () => {
    const { release } = stubHeldSearch('slow');
    const { results } = setup();
    await flush();

    // Start a held search, then navigate away (browse) before it resolves
    navigate(toSearchHash('slow', ''));
    await flush();
    expect(results.querySelector('.search-spinner')).toBeTruthy();

    navigate(toBrowseHash('elsewhere'));
    await flush();

    // The browse render cleared the results; no spinner should remain
    expect(results.querySelector('.search-spinner')).toBeNull();
    expect(results.querySelector('table')).toBeTruthy();

    // The slow search finally resolves — must not re-add a spinner or clobber
    release();
    await flush();

    expect(results.querySelector('.search-spinner')).toBeNull();
    expect(results.textContent).toContain('child-of-elsewhere');
  });

  /* ---------------------------------------------------------------------
   * Accessibility: the spinner wrapper must announce "loading" to screen
   * readers (WCAG 4.1.3 Status Messages)
   *
   * While a search fetch is in flight the previous results vanish and a
   * sighted user sees a spinning glyph, but a plain <div> wrapper is silent
   * to assistive tech — no status message is announced, violating WCAG 4.1.3.
   * The wrapper is therefore marked `role="status"` (an implicit polite live
   * region) and given an `aria-label` so its appearance is announced with a
   * meaningful message. The visual styling is untouched; the attributes are
   * purely additive.
   *
   * NOTE: this is distinct from the `aria-hidden="true"` test on the spinner
   * *icon* further below (WCAG 1.3.1 decorative glyphs) — that hides the
   * glyph from AT; these tests ensure the wrapper *is* announced as a status
   * region. Both are required: the wrapper announces while the glyph stays
   * quiet.
   * ------------------------------------------------------------------ */
  describe('spinner wrapper announces loading to assistive tech (WCAG 4.1.3)', () => {
    it('marks the spinner wrapper role="status" so its appearance is announced', async () => {
      const { release } = stubHeldSearch('slow-query');
      const { results } = setup({ hash: toSearchHash('slow-query', '') });
      await flush(); // settle the initial browse render

      navigate(toSearchHash('slow-query', ''));
      await flush();

      const spinner = results.querySelector('.search-spinner');
      expect(
        spinner,
        'a .search-spinner element must exist during an in-flight search',
      ).toBeTruthy();
      // role="status" maps to an implicit aria-live="polite" region: AT announces
      // the element when it appears, without stealing focus. A bare <div> with no
      // role is silent, so the loading state would never be announced.
      expect(spinner!.getAttribute('role')).toBe('status');

      release();
      await flush();
    });

    it('sets aria-label="Loading search results" for a meaningful announcement', async () => {
      const { release } = stubHeldSearch('slow-query');
      const { results } = setup({ hash: toSearchHash('slow-query', '') });
      await flush(); // settle the initial browse render

      navigate(toSearchHash('slow-query', ''));
      await flush();

      const spinner = results.querySelector('.search-spinner');
      expect(
        spinner,
        'a .search-spinner element must exist during an in-flight search',
      ).toBeTruthy();
      // The wrapper has no text content of its own (its only child is the
      // decorative icon), so its accessible name must come from aria-label —
      // otherwise the implicit live region would announce nothing useful when
      // the spinner appears.
      expect(spinner!.getAttribute('aria-label')).toBe('Loading search results');

      release();
      await flush();
    });
  });

  it('hides the spinner icon from assistive tech via aria-hidden="true" (WCAG 1.3.1)', async () => {
    // The spinner glyph is decorative (the loading state is conveyed by the
    // spinner's presence/animation, not by an announced glyph), so the icon
    // must be hidden from AT just like every other Bootstrap Icons glyph.
    const { release } = stubHeldSearch('slow-query');
    const { results } = setup({ hash: toSearchHash('slow-query', '') });
    await flush(); // settle the initial browse render

    navigate(toSearchHash('slow-query', ''));
    await flush();

    const spinner = results.querySelector('.search-spinner');
    expect(spinner, 'a .search-spinner element must exist during an in-flight search').toBeTruthy();
    const spinningIcon = spinner!.querySelector('.bi-arrow-repeat.spinning') as HTMLElement;
    expect(spinningIcon, 'the spinner must contain a .bi-arrow-repeat.spinning icon').toBeTruthy();
    expect(spinningIcon.getAttribute('aria-hidden')).toBe('true');

    release();
    await flush();
  });
});

export function makeIcon(name: string): HTMLElement {
  const icon = document.createElement('i');
  icon.className = 'bi bi-' + name;
  return icon;
}

